        public static F64 Sin(int degrees)
        {
            int index = degrees.CollapseDegrees();
            return F64.FromRaw(_sinRawValues[index]);
        }

        public static F64 Cos(int degrees)
        {
            // Cos has the same graph with 90 degrees shift Sin.
            int index = (degrees + 90).CollapseDegrees();
            return F64.FromRaw(_sinRawValues[index]);
        }

